class XMLSignatureUtil {

    private static final String NAMESPACE_URI = "http://www.w3.org/2000/09/xmldsig#";

    public static Document signDocument(Document document, PrivateKey privateKey, PublicKey publicKey, String referenceUri) throws Exception {
        XMLSignatureFactory signatureFactory = XMLSignatureFactory.getInstance("DOM");

        Reference reference = signatureFactory.newReference(
                referenceUri.isEmpty() ? "" : "#" + referenceUri,
                signatureFactory.newDigestMethod(DigestMethod.SHA256, null),
                Collections.singletonList(
                        signatureFactory.newTransform(Transform.ENVELOPED, (TransformParameterSpec) null)
                ),
                null, null
        );

        SignedInfo signedInfo = signatureFactory.newSignedInfo(
                signatureFactory.newCanonicalizationMethod(CanonicalizationMethod.INCLUSIVE, (C14NMethodParameterSpec) null),
                signatureFactory.newSignatureMethod(SignatureMethod.RSA_SHA256, null),
                Collections.singletonList(reference)
        );

        KeyInfoFactory keyInfoFactory = signatureFactory.getKeyInfoFactory();
        KeyValue keyValue = keyInfoFactory.newKeyValue(publicKey);
        KeyInfo keyInfo = keyInfoFactory.newKeyInfo(Collections.singletonList(keyValue));

        DOMSignContext signContext = new DOMSignContext(privateKey, document.getDocumentElement());
        XMLSignature signature = signatureFactory.newXMLSignature(signedInfo, keyInfo);
        signature.sign(signContext);

        System.out.println("[XMLSignatureUtil] Document signed successfully.");
        return document;
    }

    public static boolean verifySignature(Document document) throws Exception {
        NodeList signatureNodes = document.getElementsByTagNameNS(NAMESPACE_URI, "Signature");

        if (signatureNodes.getLength() == 0) {
            System.out.println("[XMLSignatureUtil] No XML Signature found in the document.");
            return false;
        }

        XMLSignatureFactory signatureFactory = XMLSignatureFactory.getInstance("DOM");
        DOMValidateContext validateContext = new DOMValidateContext(
                new KeyValueKeySelector(), signatureNodes.item(0)
        );

        XMLSignature signature = signatureFactory.unmarshalXMLSignature(validateContext);
        boolean isValid = signature.validate(validateContext);

        if (isValid) {
            System.out.println("[XMLSignatureUtil] XML Signature is VALID.");
        } else {
            System.out.println("[XMLSignatureUtil] XML Signature is INVALID.");
            boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
            System.out.println("[XMLSignatureUtil] Signature value validity: " + signatureValueValid);

            @SuppressWarnings("unchecked")
            List<Reference> refs = signature.getSignedInfo().getReferences();
            for (Reference ref : refs) {
                boolean refValid = ref.validate(validateContext);
                System.out.println("[XMLSignatureUtil] Reference URI=" + ref.getURI() + " validity: " + refValid);
            }
        }

        return isValid;
    }

    public static Map<String, String> extractSignedElements(Document document) throws Exception {
        Map<String, String> signedElements = new HashMap<>();
        NodeList signatureNodes = document.getElementsByTagNameNS(NAMESPACE_URI, "Signature");

        if (signatureNodes.getLength() == 0) {
            return signedElements;
        }

        XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
        DOMValidateContext validateContext = new DOMValidateContext(
                new KeyValueKeySelector(), signatureNodes.item(0)
        );
        XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

        @SuppressWarnings("unchecked")
        List<Reference> references = signature.getSignedInfo().getReferences();
        for (Reference ref : references) {
            String uri = ref.getURI();
            String digestMethod = ref.getDigestMethod().getAlgorithm();
            byte[] digestValue = ref.getDigestValue();
            String digestHex = bytesToHex(digestValue);

            signedElements.put("referenceURI", uri != null ? uri : "");
            signedElements.put("digestMethod", digestMethod);
            signedElements.put("digestValue", digestHex);
        }

        SignedInfo signedInfo = signature.getSignedInfo();
        signedElements.put("canonicalizationMethod", signedInfo.getCanonicalizationMethod().getAlgorithm());
        signedElements.put("signatureMethod", signedInfo.getSignatureMethod().getAlgorithm());

        byte[] signatureValue = signature.getSignatureValue().getValue();
        signedElements.put("signatureValue", bytesToHex(signatureValue));

        System.out.println("[XMLSignatureUtil] Extracted " + signedElements.size() + " signed element attributes.");
        return signedElements;
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    public static Document parseXmlString(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        // Prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new InputSource(new StringReader(xml)));
    }

    public static String documentToString(Document document) throws Exception {
        TransformerFactory tf = TransformerFactory.newInstance();
        Transformer transformer = tf.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(document), new StreamResult(writer));
        return writer.toString();
    }
}

