// Key Selector for signature validation
// ============================================================

class KeyValueKeySelector extends KeySelector {
    @Override
    public KeySelectorResult select(KeyInfo keyInfo, KeySelector.Purpose purpose,
                                     AlgorithmMethod method, XMLCryptoContext context) throws KeySelectorException {
        if (keyInfo == null) {
            throw new KeySelectorException("KeyInfo is null");
        }

        @SuppressWarnings("unchecked")
        List<XMLStructure> keyInfoContent = keyInfo.getContent();
        for (XMLStructure xmlStructure : keyInfoContent) {
            if (xmlStructure instanceof KeyValue) {
                try {
                    PublicKey publicKey = ((KeyValue) xmlStructure).getPublicKey();
                    return () -> publicKey;
                } catch (java.security.KeyException e) {
                    throw new KeySelectorException("Failed to obtain public key", e);
                }
            }
        }
        throw new KeySelectorException("No suitable key found in KeyInfo");
    }
}

