class WsSecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_PREFIX = "wsse";
    private static final String WSU_PREFIX = "wsu";

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, "Security", WSSE_PREFIX));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        try {
            if (isOutbound) {
                return handleOutboundMessage(context);
            } else {
                return handleInboundMessage(context);
            }
        } catch (Exception e) {
            System.err.println("[WsSecurityHandler] Error: " + e.getMessage());
            e.printStackTrace();
            throw new RuntimeException("WS-Security processing failed", e);
        }
    }

    private boolean handleOutboundMessage(SOAPMessageContext context) throws Exception {
        System.out.println("[WsSecurityHandler] Processing outbound SOAP message - adding WS-Security header and signing.");

        SOAPMessage soapMessage = context.getMessage();
        SOAPEnvelope envelope = soapMessage.getSOAPPart().getEnvelope();
        SOAPHeader header = envelope.getHeader();

        if (header == null) {
            header = envelope.addHeader();
        }

        // Add WS-Security header
        SOAPElement securityElement = header.addChildElement("Security", WSSE_PREFIX, WSSE_NS);
        securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                "http://schemas.xmlsoap.org/soap/envelope/"), "1");

        // Add Timestamp
        SOAPElement timestampElement = securityElement.addChildElement("Timestamp", WSU_PREFIX, WSU_NS);
        String timestampId = "TS-" + UUID.randomUUID().toString();
        timestampElement.addAttribute(envelope.createName("Id", WSU_PREFIX, WSU_NS), timestampId);

        Date now = new Date();
        Date expires = new Date(now.getTime() + 300000); // 5 minutes
        java.text.SimpleDateFormat sdf = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        sdf.setTimeZone(java.util.TimeZone.getTimeZone("UTC"));

        SOAPElement createdElement = timestampElement.addChildElement("Created", WSU_PREFIX, WSU_NS);
        createdElement.addTextNode(sdf.format(now));

        SOAPElement expiresElement = timestampElement.addChildElement("Expires", WSU_PREFIX, WSU_NS);
        expiresElement.addTextNode(sdf.format(expires));

        // Sign the SOAP body
        SOAPBody body = envelope.getBody();
        String bodyId = "Body-" + UUID.randomUUID().toString();
        body.addAttribute(envelope.createName("Id", WSU_PREFIX, WSU_NS), bodyId);

        // Sign the DOM document
        Document soapDocument = soapMessage.getSOAPPart();
        SecurityKeyManager keyManager = SecurityKeyManager.getInstance();
        XMLSignatureUtil.signDocument(soapDocument, keyManager.getServerPrivateKey(),
                keyManager.getServerPublicKey(), "");

        soapMessage.saveChanges();
        System.out.println("[WsSecurityHandler] Outbound message signed successfully.");
        return true;
    }

    private boolean handleInboundMessage(SOAPMessageContext context) throws Exception {
        System.out.println("[WsSecurityHandler] Processing inbound SOAP message - verifying WS-Security.");

        SOAPMessage soapMessage = context.getMessage();
        SOAPEnvelope envelope = soapMessage.getSOAPPart().getEnvelope();
        SOAPHeader header = envelope.getHeader();

        if (header == null) {
            System.out.println("[WsSecurityHandler] WARNING: No SOAP header found. Proceeding without signature verification.");
            return true;
        }

        // Check for Security header
        NodeList securityNodes = header.getElementsByTagNameNS(WSSE_NS, "Security");
        if (securityNodes.getLength() == 0) {
            System.out.println("[WsSecurityHandler] WARNING: No WS-Security header found.");
            return true;
        }

        // Verify timestamp
        verifyTimestamp(envelope);

        // Verify XML signature
        Document soapDocument = soapMessage.getSOAPPart();
        boolean signatureValid = XMLSignatureUtil.verifySignature(soapDocument);

        if (!signatureValid) {
            System.out.println("[WsSecurityHandler] ERROR: Invalid message signature detected!");
            // Extract and log signed elements for audit
            Map<String, String> signedElements = XMLSignatureUtil.extractSignedElements(soapDocument);
            for (Map.Entry<String, String> entry : signedElements.entrySet()) {
                System.out.println("[WsSecurityHandler] Signed element - " + entry.getKey() + ": " + entry.getValue());
            }
        } else {
            System.out.println("[WsSecurityHandler] Message signature verified successfully.");
            // Extract signed elements for audit trail
            Map<String, String> signedElements = XMLSignatureUtil.extractSignedElements(soapDocument);
            System.out.println("[WsSecurityHandler] Audit - Signature Method: " + signedElements.get("signatureMethod"));
            System.out.println("[WsSecurityHandler] Audit - Canonicalization: " + signedElements.get("canonicalizationMethod"));
        }

        return true;
    }

    private void verifyTimestamp(SOAPEnvelope envelope) throws SOAPException {
        SOAPHeader header = envelope.getHeader();
        NodeList timestampNodes = header.getElementsByTagNameNS(WSU_NS, "Timestamp");

        if (timestampNodes.getLength() > 0) {
            Element timestamp = (Element) timestampNodes.item(0);
            NodeList expiresNodes = timestamp.getElementsByTagNameNS(WSU_NS, "Expires");

            if (expiresNodes.getLength() > 0) {
                String expiresStr = expiresNodes.item(0).getTextContent();
                try {
                    java.text.SimpleDateFormat sdf = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
                    sdf.setTimeZone(java.util.TimeZone.getTimeZone("UTC"));
                    Date expiresDate = sdf.parse(expiresStr);

                    if (new Date().after(expiresDate)) {
                        System.out.println("[WsSecurityHandler] WARNING: Message timestamp has expired!");
                    } else {
                        System.out.println("[WsSecurityHandler] Timestamp is valid.");
                    }
                } catch (java.text.ParseException e) {
                    System.out.println("[WsSecurityHandler] WARNING: Could not parse timestamp: " + expiresStr);
                }
            }
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        System.out.println("[WsSecurityHandler] Handling SOAP fault.");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

