// ============================================================

class SOAPMessageParser {

    public static TransactionRequest parseTransactionFromSOAP(SOAPMessage soapMessage) throws Exception {
        SOAPBody body = soapMessage.getSOAPBody();
        TransactionRequest request = new TransactionRequest();

        NodeList transferNodes = body.getElementsByTagNameNS("*", "transfer");
        if (transferNodes.getLength() == 0) {
            transferNodes = body.getElementsByTagNameNS("*", "processTransaction");
        }

        if (transferNodes.getLength() > 0) {
            Element transferElement = (Element) transferNodes.item(0);

            request.setFromAccount(getElementText(transferElement, "fromAccount"));
            request.setToAccount(getElementText(transferElement, "toAccount"));
            String amountStr = getElementText(transferElement, "amount");
            if (amountStr != null && !amountStr.isEmpty()) {
                request.setAmount(new BigDecimal(amountStr));
            }
            request.setCurrency(getElementText(transferElement, "currency"));
            request.setDescription(getElementText(transferElement, "description"));

            String txId = getElementText(transferElement, "transactionId");
            if (txId != null && !txId.isEmpty()) {
                request.setTransactionId(txId);
            }
        }

        System.out.println("[SOAPMessageParser] Parsed transaction request: " + request);
        return request;
    }

    public static Map<String, String> extractSecurityHeaders(SOAPMessage soapMessage) throws Exception {
        Map<String, String> securityInfo = new HashMap<>();
        SOAPHeader header = soapMessage.getSOAPHeader();

        if (header == null) {
            return securityInfo;
        }

        String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
        String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

        NodeList securityNodes = header.getElementsByTagNameNS(WSSE_NS, "Security");
        if (securityNodes.getLength() > 0) {
            Element security = (Element) securityNodes.item(0);

            NodeList usernameTokenNodes = security.getElementsByTagNameNS(WSSE_NS, "UsernameToken");
            if (usernameTokenNodes.getLength() > 0) {
                Element usernameToken = (Element) usernameTokenNodes.item(0);
                securityInfo.put("username", getElementTextNS(usernameToken, WSSE_NS, "Username"));
            }

            NodeList timestampNodes = security.getElementsByTagNameNS(WSU_NS, "Timestamp");
            if (timestampNodes.getLength() > 0) {
                Element timestamp = (Element) timestampNodes.item(0);
                securityInfo.put("created", getElementTextNS(timestamp, WSU_NS, "Created"));
                securityInfo.put("expires", getElementTextNS(timestamp, WSU_NS, "Expires"));
            }

            // Check for signature presence
            NodeList signatureNodes = security.getElementsByTagNameNS(
                    "http://www.w3.org/2000/09/xmldsig#", "Signature");
            securityInfo.put("hasSig", String.valueOf(signatureNodes.getLength() > 0));
        }

        System.out.println("[SOAPMessageParser] Extracted security headers: " + securityInfo);
        return securityInfo;
    }

    private static String getElementText(Element parent, String localName) {
        NodeList nodes = parent.getElementsByTagNameNS("*", localName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent().trim();
        }
        return null;
    }

    private static String getElementTextNS(Element parent, String namespaceURI, String localName) {
        NodeList nodes = parent.getElementsByTagNameNS(namespaceURI, localName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent().trim();
        }
        return null;
    }
}

