    private static void runSigningDemo() throws Exception {
        System.out.println("--- XML Signature Signing & Verification Demo ---");
        System.out.println();

        // Create a sample XML document
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        DocumentBuilder db = dbf.newDocumentBuilder();
        Document doc = db.newDocument();

        Element root = doc.createElementNS("http://enterprise.banking.api/transactions", "TransactionRequest");
        doc.appendChild(root);

        Element fromAcc = doc.createElement("FromAccount");
        fromAcc.setTextContent("ACC001");
        root.appendChild(fromAcc);

        Element toAcc = doc.createElement("ToAccount");
        toAcc.setTextContent("ACC002");
        root.appendChild(toAcc);

        Element amount = doc.createElement("Amount");
        amount.setTextContent("10000.00");
        root.appendChild(amount);

        Element currency = doc.createElement("Currency");
        currency.setTextContent("USD");
        root.appendChild(currency);

        System.out.println("[SigningDemo] Original XML:");
        System.out.println(XMLSignatureUtil.documentToString(doc));
        System.out.println();

        // Sign the document
        SecurityKeyManager keyManager = SecurityKeyManager.getInstance();
        Document signedDoc = XMLSignatureUtil.signDocument(doc,
                keyManager.getServerPrivateKey(), keyManager.getServerPublicKey(), "");

        System.out.println("[SigningDemo] Signed XML:");
        System.out.println(XMLSignatureUtil.documentToString(signedDoc));
        System.out.println();

        // Verify the signature
        boolean isValid = XMLSignatureUtil.verifySignature(signedDoc);
        System.out.println("[SigningDemo] Signature verification result: " + isValid);
        System.out.println();

        // Extract signed elements
        Map<String, String> signedElements = XMLSignatureUtil.extractSignedElements(signedDoc);
        System.out.println("[SigningDemo] Extracted signed elements:");
        for (Map.Entry<String, String> entry : signedElements.entrySet()) {
            System.out.println("  " + entry.getKey() + " = " + entry.getValue());
        }
        System.out.println();

        // Tamper with the document and verify again
        NodeList amountNodes = signedDoc.getElementsByTagName("Amount");
        if (amountNodes.getLength() > 0) {
            amountNodes.item(0).setTextContent("99999.00");
        }
        System.out.println("[SigningDemo] After tampering with Amount field:");
        boolean isValidAfterTamper = XMLSignatureUtil.verifySignature(signedDoc);
        System.out.println("[SigningDemo] Signature verification after tamper: " + isValidAfterTamper);
        AuditLogger.logSecurityEvent("TAMPER_DETECTION_TEST",
                "Tampered document verification result: " + isValidAfterTamper);
        System.out.println();
    }

